// Benchmark inspection smoke fixture: external LED on Arduino Uno pin 13.
// The circuit routes pin 13 through a 220-ohm resistor and LED to ground.

constexpr int LED_PIN = 13;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  digitalWrite(LED_PIN, HIGH);
  delay(500);
  digitalWrite(LED_PIN, LOW);
  delay(500);
}

constexpr int POT_PIN = A1;
constexpr int PWM_PIN = 3;

unsigned long lastReportMs = 0;

void setup() {
  pinMode(PWM_PIN, OUTPUT);
  Serial.begin(115200);
}

void loop() {
  const unsigned long now = millis();
  if (now - lastReportMs < 100) return;
  lastReportMs = now;

  const int adc = analogRead(POT_PIN);
  const int duty = map(adc, 0, 1023, 0, 255);
  analogWrite(PWM_PIN, duty);
  Serial.print("ADC=");
  Serial.print(adc);
  Serial.print(" PWM=");
  Serial.println(duty);
}

// active_low_interlock (OS-D1-01) — reference solution.
// Button on D2 (INPUT_PULLUP, to GND): released=HIGH, pressed=LOW.
// LED on D7 through an inverting stage → active-low: LOW = on, HIGH = off.
// LED off at startup; on while pressed, off while released; follow continuously.

const int BUTTON_PIN = 2;
const int LED_PIN = 7;

void setup() {
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, HIGH); // active-low: HIGH = off
}

void loop() {
  bool pressed = digitalRead(BUTTON_PIN) == LOW;
  digitalWrite(LED_PIN, pressed ? LOW : HIGH);
}

// dual_input_safety_enable (OS-D1-02) — reference solution.
// Two normally-open switches to ground on D4/D5 (INPUT_PULLUP → closed = LOW).
// Active-high ENABLE on D8 is HIGH only while BOTH switches are closed.

const int SW1_PIN = 4;
const int SW2_PIN = 5;
const int ENABLE_PIN = 8;

void setup() {
  pinMode(SW1_PIN, INPUT_PULLUP);
  pinMode(SW2_PIN, INPUT_PULLUP);
  pinMode(ENABLE_PIN, OUTPUT);
  digitalWrite(ENABLE_PIN, LOW);
}

void loop() {
  bool both = digitalRead(SW1_PIN) == LOW && digitalRead(SW2_PIN) == LOW;
  digitalWrite(ENABLE_PIN, both ? HIGH : LOW);
}

// tmp36_calibrated_report (OS-D1-03) — reference solution.
// TMP36 on A0: ADC ref 5.0 V, 0..1023; 0.500 V at 0 °C, 0.010 V/°C.
// Print TEMP_C=x.x (one decimal) every 250 ms at 115200 baud; first line < 300 ms.

const int SENSOR_PIN = A0;

void setup() {
  Serial.begin(115200);
}

void loop() {
  int raw = analogRead(SENSOR_PIN);
  float volts = raw * (5.0 / 1023.0);
  float tempC = (volts - 0.5) / 0.01;
  Serial.print("TEMP_C=");
  Serial.println(tempC, 1);
  delay(250);
}

// potentiometer_pwm_map (OS-D1-04) — reference solution.
// Pot on A1 → PWM LED on D3. Linearly map ADC 0..1023 to duty 0..255, clamped,
// refreshed at least every 20 ms.

const int POT_PIN = A1;
const int LED_PIN = 3;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  int raw = analogRead(POT_PIN);
  int duty = map(raw, 0, 1023, 0, 255);
  duty = constrain(duty, 0, 255);
  analogWrite(LED_PIN, duty);
  delay(10);
}

// hex_dip_to_7segment (OS-D1-05) — reference solution.
// DIP switches D2..D5 (INPUT_PULLUP, closed = LOW = 1; D2 = bit0, D5 = bit3) form
// a 4-bit value. Common-cathode seven-segment: segments a..g on D6..D12, active-high.
// Show the value as one uppercase hex digit (A b C d E F for 10..15).

const int SW_PINS[4] = {2, 3, 4, 5};      // bit 0..3
const int SEG_PINS[7] = {6, 7, 8, 9, 10, 11, 12}; // a..g

// Bit 6 = segment a … bit 0 = segment g (active-high).
const byte FONT[16] = {
  0b1111110, // 0
  0b0110000, // 1
  0b1101101, // 2
  0b1111001, // 3
  0b0110011, // 4
  0b1011011, // 5
  0b1011111, // 6
  0b1110000, // 7
  0b1111111, // 8
  0b1111011, // 9
  0b1110111, // A
  0b0011111, // b
  0b1001110, // C
  0b0111101, // d
  0b1001111, // E
  0b1000111, // F
};

void setup() {
  for (int i = 0; i < 4; i++) pinMode(SW_PINS[i], INPUT_PULLUP);
  for (int i = 0; i < 7; i++) pinMode(SEG_PINS[i], OUTPUT);
}

void loop() {
  int value = 0;
  for (int i = 0; i < 4; i++) {
    if (digitalRead(SW_PINS[i]) == LOW) value |= (1 << i);
  }
  byte pattern = FONT[value];
  for (int i = 0; i < 7; i++) {
    digitalWrite(SEG_PINS[i], (pattern >> (6 - i)) & 1 ? HIGH : LOW);
  }
}

// debounced_toggle (OS-D2-02) — reference solution.
// Button D2 (INPUT_PULLUP, to GND): released=HIGH, pressed=LOW.
// Active-low LED on D7 (LOW = on). Toggle once per DEBOUNCED press; a level must
// be stable for >=30 ms before it counts; holding does not repeat — a further
// toggle needs a debounced release then a new debounced press.

const int BTN_PIN = 2;
const int LED_PIN = 7;
const unsigned long DEBOUNCE_MS = 30;

int ledState = HIGH;        // active-low: HIGH = off at startup
int stableLevel = HIGH;     // debounced button level (HIGH = released)
int lastReading = HIGH;
unsigned long lastChangeMs = 0;

void setup() {
  pinMode(BTN_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, ledState);
}

void loop() {
  int reading = digitalRead(BTN_PIN);
  if (reading != lastReading) {
    lastReading = reading;
    lastChangeMs = millis();
  }
  if (millis() - lastChangeMs >= DEBOUNCE_MS && reading != stableLevel) {
    stableLevel = reading;
    if (stableLevel == LOW) {            // a newly debounced press
      ledState = (ledState == HIGH) ? LOW : HIGH;
      digitalWrite(LED_PIN, ledState);
    }
  }
}

// light_alarm_hysteresis (OS-D2-03) — reference solution.
// Light sensor ADC on A2; active-high warning LED on D6.
// LED on at reading <= 350, off at reading >= 450, HOLD state in between.
// LED starts off. Sample at least every 20 ms.

const int SENSOR_PIN = A2;
const int LED_PIN = 6;
const int ON_AT = 350;   // reading <= 350 -> on
const int OFF_AT = 450;  // reading >= 450 -> off

bool alarmOn = false;

void setup() {
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW); // off
}

void loop() {
  int reading = analogRead(SENSOR_PIN);
  if (reading <= ON_AT) {
    alarmOn = true;
  } else if (reading >= OFF_AT) {
    alarmOn = false;
  } // strictly between: retain previous state
  digitalWrite(LED_PIN, alarmOn ? HIGH : LOW);
  delay(20);
}

// responsive_dual_scheduler (OS-D2-01) — reference solution.
// Three concurrent behaviours, non-blocking:
//   - LED A (D3): 1 Hz, 50% duty  → toggle every 500 ms
//   - LED B (D5): 2 Hz, 50% duty  → toggle every 250 ms
//   - Response LED (D8): mirrors the button (D2, INPUT_PULLUP) within 20 ms while
//     both blink patterns continue uninterrupted.
// All three outputs start LOW.

const int LED_A = 3;
const int LED_B = 5;
const int RESP  = 8;
const int BTN   = 2;

unsigned long tA = 0, tB = 0;
bool aOn = false, bOn = false;

void setup() {
  pinMode(LED_A, OUTPUT);
  pinMode(LED_B, OUTPUT);
  pinMode(RESP, OUTPUT);
  pinMode(BTN, INPUT_PULLUP);
  digitalWrite(LED_A, LOW);
  digitalWrite(LED_B, LOW);
  digitalWrite(RESP, LOW);
}

void loop() {
  unsigned long now = millis();
  if (now - tA >= 500) { tA = now; aOn = !aOn; digitalWrite(LED_A, aOn); }
  if (now - tB >= 250) { tB = now; bOn = !bOn; digitalWrite(LED_B, bOn); }
  // Runs every loop iteration (microseconds) → button mirrored well within 20 ms.
  digitalWrite(RESP, digitalRead(BTN) == LOW ? HIGH : LOW);
}

// rolling_adc_average (OS-D2-04) — reference solution.
// A0 sampled every 25 ms. Once eight samples exist, after each new sample print
// the truncated integer mean of the most recent eight as "AVG=<n>". Print nothing
// before the eighth sample.

const int SENSOR_PIN = A0;
const unsigned long PERIOD_MS = 25;
const int WINDOW = 8;

int samples[WINDOW];
int idx = 0;
int filled = 0;
unsigned long tNext = 0;

void setup() {
  Serial.begin(115200);
}

void loop() {
  unsigned long now = millis();
  if ((long)(now - tNext) < 0) return;
  tNext = now + PERIOD_MS;

  samples[idx] = analogRead(SENSOR_PIN);
  idx = (idx + 1) % WINDOW;
  if (filled < WINDOW) filled++;

  if (filled == WINDOW) {
    long sum = 0;
    for (int i = 0; i < WINDOW; i++) sum += samples[i];
    long avg = sum / WINDOW;            // truncated toward zero (readings >= 0)
    Serial.print("AVG=");
    Serial.println(avg);
  }
}

// integer_overflow_accumulator (OS-D2-05) — reference solution.
// Line-oriented stats over Serial @115200. Each line is a signed decimal integer
// in [-32768, 32767] or the exact word RESET. For each accepted integer, update
// count/sum/min/max since the last reset and reply:
//   N=k SUM=s MIN=lo MAX=hi
// The running SUM can exceed the range of a single value, so it must NOT live in a
// 16-bit int (that overflows after two full-magnitude samples). A 32-bit long is
// sufficient; this reference uses a 64-bit accumulator (with a printInt64 helper)
// to stay exact indefinitely. RESET zeroes all stats. A malformed/empty/out-of-range
// line replies ERR and changes nothing. An overlong line is discarded through its
// terminator with a single ERR.

const int MAX_LINE = 15;

char line[MAX_LINE + 1];
int len = 0;
bool overlong = false;

long long sumTotal = 0;   // 64-bit: exact well past 100000 full-magnitude samples
unsigned long count = 0;
long minV = 0, maxV = 0;

void printInt64(long long v) {
  if (v < 0) { Serial.print('-'); v = -v; }
  char tmp[20];
  int i = 0;
  if (v == 0) { Serial.print('0'); return; }
  unsigned long long u = (unsigned long long)v;
  while (u > 0) { tmp[i++] = char('0' + (int)(u % 10)); u /= 10; }
  while (i > 0) Serial.print(tmp[--i]);
}

void report() {
  Serial.print("N=");
  Serial.print(count);
  Serial.print(" SUM=");
  printInt64(sumTotal);
  Serial.print(" MIN=");
  Serial.print(minV);
  Serial.print(" MAX=");
  Serial.print(maxV);
  Serial.print('\n');
}

void resetStats() {
  sumTotal = 0;
  count = 0;
  minV = 0;
  maxV = 0;
  report();
}

void processLine() {
  line[len] = '\0';
  if (len == 5 && strcmp(line, "RESET") == 0) { resetStats(); return; }
  if (len == 0) { Serial.println("ERR"); return; }

  int i = 0;
  bool neg = false;
  if (line[0] == '-') { neg = true; i = 1; if (len == 1) { Serial.println("ERR"); return; } }
  long val = 0;
  for (; i < len; i++) {
    if (line[i] < '0' || line[i] > '9') { Serial.println("ERR"); return; }
    val = val * 10 + (line[i] - '0');
    if (val > 100000L) { Serial.println("ERR"); return; } // overflow guard for parse
  }
  if (neg) val = -val;
  if (val < -32768L || val > 32767L) { Serial.println("ERR"); return; }

  count++;
  sumTotal += (long long)val;
  if (count == 1) { minV = val; maxV = val; }
  else { if (val < minV) minV = val; if (val > maxV) maxV = val; }
  report();
}

void setup() {
  Serial.begin(115200);
}

void loop() {
  while (Serial.available()) {
    char c = Serial.read();
    if (c == '\r') continue;
    if (c == '\n') {
      if (overlong) { Serial.println("ERR"); overlong = false; }
      else processLine();
      len = 0;
      continue;
    }
    if (len >= MAX_LINE) overlong = true; // stop storing; wait for the terminator
    else line[len++] = c;
  }
}
